mapper.select:
SELECT DATE_FORMAT(bill_time, '%Y-%m-%d') AS date, SUM(CASE WHEN bill_type = 1 THEN amount ELSE 0 END) AS income, SUM(CASE WHEN bill_type = 2 THEN amount ELSE 0 END) AS expense FROM bill_record WHERE bill_time >= DATE_SUB(CURDATE(), INTERVAL #{days} DAY)
AND user_id = #{userId}
GROUP BY DATE_FORMAT(bill_time, '%Y-%m-%d') ORDER BY date ASC

SELECT bc.id AS categoryId, bc.category_name AS categoryName, bc.icon AS icon, SUM(CASE WHEN br.bill_type = 1 THEN br.amount ELSE 0 END) AS income, SUM(CASE WHEN br.bill_type = 2 THEN br.amount ELSE 0 END) AS expense, SUM(CASE WHEN br.bill_type = 1 THEN br.amount ELSE -br.amount END) AS total FROM bill_category bc LEFT JOIN bill_record br ON bc.id = br.category_id WHERE 1=1
AND br.user_id = #{userId}
AND br.bill_type = #{billType}
AND br.bill_time >= #{startDate}
AND br.bill_time <= #{endDate}
GROUP BY bc.id, bc.category_name, bc.icon HAVING total != 0 ORDER BY ABS(total) DESC

SELECT DATE_FORMAT(br.bill_time, '%Y-%m-%d') AS date, bc.category_name AS categoryName, br.payment AS payment, SUM(br.amount) AS amount FROM bill_record br LEFT JOIN bill_category bc ON br.category_id = bc.id WHERE br.bill_type = 1 AND br.bill_time >= DATE_SUB(CURDATE(), INTERVAL 15 DAY)
AND br.user_id = #{userId}
GROUP BY DATE_FORMAT(br.bill_time, '%Y-%m-%d'), bc.category_name, br.payment ORDER BY date ASC, amount DESC

SELECT DATE_FORMAT(br.bill_time, '%Y-%m-%d') AS date, bc.category_name AS categoryName, br.payment AS payment, SUM(br.amount) AS amount FROM bill_record br LEFT JOIN bill_category bc ON br.category_id = bc.id WHERE br.bill_type = 2 AND br.bill_time >= DATE_SUB(CURDATE(), INTERVAL 15 DAY)
AND br.user_id = #{userId}
GROUP BY DATE_FORMAT(br.bill_time, '%Y-%m-%d'), bc.category_name, br.payment ORDER BY date ASC, amount DESC

SELECT br.*
FROM bill_record br
WHERE br.bill_type = 1

    AND br.user_id = #{userId}

ORDER BY br.bill_time DESC, br.created DESC
LIMIT #{limit}

SELECT br.*
FROM bill_record br
WHERE br.bill_type = 2

    AND br.user_id = #{userId}

ORDER BY br.bill_time DESC, br.created DESC
LIMIT #{limit}

SELECT br.payment AS payment, SUM(CASE WHEN br.bill_type = 1 THEN br.amount ELSE 0 END) AS income, SUM(CASE WHEN br.bill_type = 2 THEN br.amount ELSE 0 END) AS expense, SUM(CASE WHEN br.bill_type = 1 THEN br.amount ELSE -br.amount END) AS total FROM bill_record br WHERE 1=1
AND br.user_id = #{userId}
AND br.bill_type = #{billType}
AND br.bill_time >= #{startDate}
AND br.bill_time <= #{endDate}
AND br.payment IS NOT NULL AND br.payment != '' GROUP BY br.payment HAVING total != 0 ORDER BY ABS(total) DESC
